request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?owned ?ownedName ?ownedType WHERE {
  ?aps vocab:NamedElement_name "APS%20Mission" .
  ?aps vocab:Element_ownedElement ?owned .
  OPTIONAL { ?owned vocab:NamedElement_name ?ownedName }
  OPTIONAL { ?owned rdf:type ?ownedType }
}
LIMIT 30
